/* ══════════════════════════════════════════════════════════
   ABOUT DROPDOWN
══════════════════════════════════════════════════════════ */

/* Nav item that owns a dropdown */
.nav-has-dropdown {
  position: relative;
}

/* The trigger button — styled like a normal nav link */
.nav-dropdown-trigger {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  font-family: inherit;
  font-size: inherit;
  font-weight: inherit;
  letter-spacing: inherit;
  color: inherit;
  text-transform: inherit;
  transition: color 0.25s;
}

.nav-dropdown-trigger.active,
.nav-has-dropdown:hover .nav-dropdown-trigger {
  color: #d4af37;
}

/* Chevron icon */
.nav-chevron {
  transition: transform 0.3s cubic-bezier(0.22, 1, 0.36, 1);
  opacity: 0.55;
  flex-shrink: 0;
}

.nav-chevron.open {
  transform: rotate(180deg);
  opacity: 1;
}

/* Dropdown panel */
.nav-dropdown {
  position: absolute;
  top: calc(100% + 18px);
  left: 50%;
  transform: translateX(-50%) translateY(-8px);
  min-width: 160px;
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  transition:
    opacity 0.28s cubic-bezier(0.22, 1, 0.36, 1),
    transform 0.28s cubic-bezier(0.22, 1, 0.36, 1),
    visibility 0.28s;
  z-index: 200;
}

.nav-dropdown.is-open {
  opacity: 1;
  visibility: visible;
  pointer-events: auto;
  transform: translateX(-50%) translateY(0);
}

/* Arrow tip pointing up */
.nav-dropdown::before {
  content: '';
  position: absolute;
  top: -6px;
  left: 50%;
  transform: translateX(-50%);
  width: 12px;
  height: 6px;
  clip-path: polygon(50% 0%, 0% 100%, 100% 100%);
  background: rgba(212, 175, 55, 0.18);
}

.nav-dropdown-inner {
  background: rgba(6, 6, 16, 0.97);
  border: 1px solid rgba(212, 175, 55, 0.18);
  border-radius: 14px;
  padding: 8px;
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  box-shadow:
    0 24px 64px rgba(0, 0, 0, 0.65),
    0 0 0 1px rgba(255, 255, 255, 0.04) inset;
  overflow: hidden;
}

/* Each dropdown link */
.nav-dropdown-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 16px;
  border-radius: 9px;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 2.5px;
  text-transform: uppercase;
  color: rgba(242, 238, 234, 0.55);
  text-decoration: none;
  transition: color 0.22s, background 0.22s;
  white-space: nowrap;
  position: relative;
}

.nav-dropdown-item:hover {
  color: #d4af37;
  background: rgba(212, 175, 55, 0.07);
}

.nav-dropdown-item.active {
  color: #d4af37;
  background: rgba(212, 175, 55, 0.1);
}

/* Gold dot accent */
.nav-dropdown-dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: currentColor;
  opacity: 0.5;
  flex-shrink: 0;
  transition: opacity 0.22s, transform 0.22s;
}

.nav-dropdown-item:hover .nav-dropdown-dot,
.nav-dropdown-item.active .nav-dropdown-dot {
  opacity: 1;
  transform: scale(1.4);
}

/* Divider between items */
.nav-dropdown-item + .nav-dropdown-item::before {
  content: '';
  position: absolute;
  top: 0;
  left: 16px;
  right: 16px;
  height: 1px;
  background: rgba(255, 255, 255, 0.05);
}

/* ── Mobile: show as accordion inside nav ── */
@media (max-width: 900px) {
  .nav-dropdown {
    position: static;
    transform: none;
    left: auto;
    min-width: unset;
    opacity: 1;
    visibility: visible;
    pointer-events: auto;
    display: none;
    padding-top: 4px;
  }

  .nav-dropdown.is-open {
    display: block;
    transform: none;
  }

  .nav-dropdown::before { display: none; }

  .nav-dropdown-inner {
    background: rgba(212, 175, 55, 0.04);
    border: none;
    border-left: 1px solid rgba(212, 175, 55, 0.2);
    border-radius: 0;
    padding: 4px 0 4px 16px;
    box-shadow: none;
    backdrop-filter: none;
  }

  .nav-dropdown-item {
    font-size: 11px;
    padding: 8px 12px;
  }
}
